mapper.select:
SELECT gui.id, COALESCE(ga.title, '未知活动') AS title, COALESCE(ga.cpu, '待定') AS cpu, COALESCE(ga.memory, '待定') AS memory, COALESCE(ga.storage, '待定') AS storage, gui.custom_price AS base_price, gui.duration AS total_duration, gui.current_num, gui.min_num AS group_min_num, gui.max_num AS group_max_num, CASE WHEN gui.group_status = 0 THEN 1 -- 招募中 -> 进行中 WHEN gui.group_status = 1 THEN 2 -- 已成团 -> 拼团成功 WHEN gui.group_status = 2 THEN 3 -- 已取消/过期 -> 已结束 ELSE 1 END AS status, gui.initiate_time AS start_time, gui.server_start_time, gui.server_expire_time AS server_end_time, ga.server_tutorial_url, ga.cover FROM osh_group_user_initiated gui LEFT JOIN osh_group_activity ga ON gui.activity_id = ga.id 20250528 gui.delete_flag = 0
AND ( CASE WHEN gui.group_status = 0 THEN 1 WHEN gui.group_status = 1 THEN 2 WHEN gui.group_status = 2 THEN 3 ELSE 1 END ) = #{status}
ORDER BY gui.initiate_time DESC


WHERE user_id = #{userId} AND delete_flag = 0

    AND group_status = #{groupStatus}

ORDER BY initiate_time DESC

mapper.update:
UPDATE osh_group_user_initiated
order_id = #{orderId}, min_num = #{minNum}, max_num = #{maxNum}, duration = #{duration}, custom_price = #{customPrice}, group_status = #{groupStatus}, current_num = #{currentNum}, server_ip = #{serverIp}, server_account = #{serverAccount}, server_password = #{serverPassword}, server_start_time = #{serverStartTime}, server_expire_time = #{serverExpireTime}, expire_time = #{expireTime}, delete_flag = #{deleteFlag}, update_time = NOW(),
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) 
FROM (
    -- 检查是否是发起人
    SELECT user_id 
    FROM osh_group_user_initiated
    WHERE id = #{activityId} 
      AND user_id = #{userId}
      AND delete_flag = 0
    UNION ALL
    -- 检查是否已作为参团成员加入
    SELECT user_id
    FROM osh_group_work
    WHERE group_activity_id = #{activityId}
      AND user_id = #{userId}
) AS combined
